// Validate and unpack incoming payload
const body = $input.first().json.body || $input.first().json;

const required = ['content_type', 'raw_content', 'product_category'];
const missing = required.filter(k => !body[k]);

if (missing.length > 0) {
  return [{ json: {
    error: true,
    message: `Missing required fields: ${missing.join(', ')}`,
    received: Object.keys(body)
  }}];
}

// Normalize content type
const typeMap = {
  'ebook': 'ebook',
  'ebook_chapter': 'ebook',
  'guide': 'ebook',
  'listing': 'listing',
  'title': 'listing',
  'description': 'listing',
  'social': 'social',
  'caption': 'social',
  'tiktok': 'social',
  'instagram': 'social',
  'facebook': 'social',
  'pinterest': 'social',
  'sd_prompt': 'sd_prompt',
  'image_prompt': 'sd_prompt',
  'art_prompt': 'sd_prompt'
};

const normalizedType = typeMap[body.content_type?.toLowerCase()] || body.content_type;

// Detect tone from product category
const category = (body.product_category || '').toLowerCase();
const productName = (body.product_name || '').toLowerCase();

let detectedTone = 'friendly_relatable';
let toneDescription = '';

if (category.includes('productivity') || category.includes('notion') || category.includes('planner') || productName.includes('productivity') || productName.includes('planner')) {
  detectedTone = 'professional_warm';
  toneDescription = 'Professional but approachable. Like a smart friend who has their life together and wants to help you get yours together too. Efficient language, practical tone, light encouragement.';
} else if (category.includes('ai art') || category.includes('watercolor') || category.includes('illustration') || category.includes('art pack')) {
  detectedTone = 'creative_expressive';
  toneDescription = 'Artistic and expressive. Evocative language that makes people feel the beauty of the art. Descriptive, sensory, emotional. Like a passionate artist talking about their work.';
} else if (category.includes('ebook') || category.includes('guide') || category.includes('how to') || productName.includes('guide') || productName.includes('tips')) {
  detectedTone = 'mentor_casual';
  toneDescription = 'Like a knowledgeable friend teaching over coffee. Casual but substantive. Uses "you" and "your" a lot. Cuts fluff. Gets to the point fast. Occasionally uses humor.';
} else if (category.includes('printable') || category.includes('template') || category.includes('canva')) {
  detectedTone = 'cheerful_helpful';
  toneDescription = 'Cheerful, enthusiastic, helpful. Like a creative friend who loves sharing cool finds. Upbeat but not annoying. Excited about design and organization.';
} else if (category.includes('budget') || category.includes('finance') || category.includes('money')) {
  detectedTone = 'trustworthy_empathetic';
  toneDescription = 'Trustworthy and empathetic. Acknowledges that money is stressful. Non-judgmental. Clear and simple language. No jargon. Reassuring without being condescending.';
} else if (category.includes('fitness') || category.includes('wellness') || category.includes('health')) {
  detectedTone = 'motivational_real';
  toneDescription = 'Motivational but real — not toxic positivity. Acknowledges the struggle. Uses direct, punchy sentences. Action-oriented. Like a coach who actually gets it.';
} else {
  detectedTone = 'friendly_relatable';
  toneDescription = 'Warm, relatable, and genuine. Speaks like a real person — not a brand. Occasional personality. Gets to the point. Uses simple, clear language with a friendly energy.';
}

return [{
  json: {
    ...body,
    content_type: normalizedType,
    original_type: body.content_type,
    detected_tone: detectedTone,
    tone_description: toneDescription,
    product_category: body.product_category,
    product_name: body.product_name || '',
    raw_content: body.raw_content,
    _validated: true,
    _received_at: new Date().toISOString()
  }
}];

// Parse prompt engineer output and extract the recommended variant
const raw = $input.first().json;
const inputData = $('🔀 Route by Content Type').first().json;

let engineered;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  engineered = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  // Fallback: return original prompt with basic enhancements
  engineered = {
    error: true,
    optimized_prompts: {
      safe: {
        prompt: inputData.raw_content + ', masterpiece, best quality, highly detailed, 8k resolution, professional photography, sharp focus, commercial art',
        negative_prompt: 'blurry, watermark, text, signature, low quality, bad anatomy, distorted',
        aspect_ratio: '1:1',
        cfg_scale: 7,
        steps: 30
      }
    },
    recommended_variant: 'safe'
  };
}

// Pick the recommended variant
const recommended = engineered.recommended_variant || 'safe';
const bestPrompt = engineered.optimized_prompts?.[recommended] || engineered.optimized_prompts?.safe;

return [{
  json: {
    // Pass back to caller
    content_type: 'sd_prompt',
    product_name: inputData.product_name,
    product_category: inputData.product_category,
    original_prompt: inputData.raw_content,

    // Engineered output
    engineered_prompt: bestPrompt?.prompt,
    negative_prompt: bestPrompt?.negative_prompt,
    aspect_ratio: bestPrompt?.aspect_ratio || '1:1',
    cfg_scale: bestPrompt?.cfg_scale || 7,
    steps: bestPrompt?.steps || 30,
    style_notes: bestPrompt?.style_notes,
    recommended_variant: recommended,
    recommendation_reason: engineered.recommendation_reason,

    // All variants for reference
    all_variants: engineered.optimized_prompts,
    analysis: engineered.analysis,
    quality_boosters: engineered.quality_boosters_added,

    // Metadata
    agent: 'prompt_engineer_mistral',
    processed_at: new Date().toISOString(),
    _ready: true
  }
}];

