// Quality gate — score the humanized content before returning it
// Catches cases where Ollama output still has AI tells

const items = $input.all();
const results = [];

// AI giveaway phrases to scan for
const aiBuzzwords = [
  'delve into', 'leverage', "it's worth noting", 'game-changer',
  'in conclusion', 'furthermore', 'moreover', 'utilize', 'facilitate',
  'in the realm of', 'embark on', 'navigate', 'paradigm', 'holistic',
  'robust', 'seamlessly', 'synergy', 'transformative', 'foster',
  'pivotal', 'actionable insights', 'at the end of the day',
  'in today\'s fast-paced', 'look no further', 'elevate your',
  'take your', 'to the next level', 'don\'t miss out'
];

for (const item of items) {
  const data = item.json;

  // Get all text content to scan
  const allText = JSON.stringify(data).toLowerCase();

  const foundPhrases = aiBuzzwords.filter(phrase => allText.includes(phrase.toLowerCase()));
  const aiScore = foundPhrases.length;

  // Quality assessment
  let quality = 'excellent';
  let needsRetry = false;

  if (aiScore >= 5) {
    quality = 'poor';
    needsRetry = true;
  } else if (aiScore >= 3) {
    quality = 'fair';
    needsRetry = false; // Accept but flag
  } else if (aiScore >= 1) {
    quality = 'good';
  }

  results.push({
    json: {
      ...data,
      _quality_gate: {
        score: quality,
        ai_phrases_remaining: foundPhrases,
        ai_phrase_count: aiScore,
        needs_retry: needsRetry,
        gate_passed: aiScore < 5,
        checked_at: new Date().toISOString()
      }
    }
  });
}

return results;

