// Merge quality-passed and retry outputs into single response
const passedItems = $('🔀 Quality Good Enough?').all().filter(i => !i.json._quality_gate?.needs_retry);
const retryItems = $input.all();

const allItems = [...passedItems, ...retryItems];

// Build final response payload
const finalOutputs = allItems.map(item => {
  const data = item.json;
  return {
    json: {
      success: true,
      content_type: data.content_type || data._agent?.replace('_humanizer','').replace('_agent',''),
      product_name: data._product_name,
      product_category: data._product_category,
      tone_applied: data._tone_applied,
      quality_score: data._quality_gate?.score || 'good',
      ai_phrases_remaining: data._quality_gate?.ai_phrase_count || 0,

      // Content outputs by type
      humanized_content: data.humanized_content || null,         // ebook
      humanized_title: data.humanized_title || null,             // listing
      humanized_description_short: data.humanized_description_short || null,
      humanized_description_long: data.humanized_description_long || null,
      humanized_tags: data.humanized_tags || null,
      instagram: data.instagram || null,                         // social
      facebook: data.facebook || null,
      tiktok: data.tiktok || null,
      pinterest: data.pinterest || null,
      youtube_shorts: data.youtube_shorts || null,

      // Prompt engineer specific
      engineered_prompt: data.engineered_prompt || null,
      negative_prompt: data.negative_prompt || null,
      cfg_scale: data.cfg_scale || null,
      steps: data.steps || null,
      all_variants: data.all_variants || null,

      _metadata: {
        processed_at: new Date().toISOString(),
        agents_used: data._agent || 'multiple',
        retried: retryItems.includes(item)
      }
    }
  };
});

return finalOutputs.length > 0 ? finalOutputs : [{ json: { success: false, error: 'No outputs produced' } }];
